return clients.map(c => ({ json: c }));

const client = $('Client List').item.json;
const data = $json;
const contacts = data.contacts || [];
const sources = {};
contacts.forEach(c => { const s = c.source || c.tags?.[0] || 'Direct'; sources[s] = (sources[s]||0)+1; });
const topSources = Object.entries(sources).sort((a,b)=>b[1]-a[1]).slice(0,5).map(([k,v])=>k+': '+v).join(', ') || 'No data';
const now = new Date();
const thirtyAgo = new Date(now.getTime() - 30*24*60*60*1000);
return [{ json: {
  ...client,
  totalContacts: contacts.length,
  topSources,
  monthName: now.toLocaleString('en-US', { month: 'long', year: 'numeric' }),
  period: thirtyAgo.toISOString().split('T')[0] + ' to ' + now.toISOString().split('T')[0]
}}];

