const client = $('Process Data').item.json;
const report = $json.choices[0].message.content;
const monthName = client.monthName;
const rHtml = report.replace(/\n/g, '<br>').replace(/\*\*(.*?)\*\*/g, '<b>$1</b>');
const subjectPrefix = client.originalEmail ? '[TEST → would go to ' + client.originalEmail + '] ' : '';

const html = '<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px;color:#333;background:#f5f5f5;">' +
'<div style="background:linear-gradient(135deg,#0d1b2a,#1a237e);padding:30px;border-radius:12px 12px 0 0;text-align:center;">' +
'<h1 style="color:#ffd700;margin:0;font-size:22px;">Galaxy IT &amp; Marketing</h1>' +
'<p style="color:rgba(255,255,255,0.7);margin:8px 0 0;font-size:14px;">Monthly Performance Report &mdash; ' + monthName + '</p>' +
'<p style="color:rgba(255,255,255,0.5);margin:4px 0 0;font-size:12px;">Client: ' + client.name + '</p>' +
'</div>' +
'<div style="background:#fff;padding:30px;border:1px solid #e5e5e5;border-top:none;">' +
'<div style="text-align:center;background:#f8f9fa;padding:20px;border-radius:8px;border-top:3px solid #ffd700;margin-bottom:20px;">' +
'<div style="font-size:32px;font-weight:800;color:#1a237e;">' + client.totalContacts + '</div>' +
'<div style="font-size:11px;color:#888;margin-top:4px;">Total Contacts in CRM</div>' +
'</div>' +
'<p style="font-size:14px;line-height:1.8;">' + rHtml + '</p>' +
'</div>' +
'<div style="background:#f8f9fa;padding:20px;border-radius:0 0 12px 12px;text-align:center;border:1px solid #e5e5e5;border-top:none;">' +
'<p style="margin:0;font-size:12px;color:#888;">Questions? <a href="https://galaxyinfo.us/support" style="color:#1a237e;font-weight:600;">Help Center</a></p>' +
'<p style="margin:8px 0 0;font-size:11px;color:#aaa;">&copy; 2026 Galaxy IT &amp; Marketing</p>' +
'</div></body></html>';

return [{ json: { ...client, report, html, subject: subjectPrefix + 'Monthly Report — ' + client.name + ' — ' + monthName } }];
